custom_css:
/* Navigation rapide */
.training-navigation nav ul {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  list-style: none;
  padding: 0;
  margin: 0;
}

.training-navigation nav ul li {
  margin: 0;
}

/* Section calendrier */
.calendar-section {
  background: linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%);
  padding: 2rem;
  border-radius: 1rem;
  margin: 2rem 0;
}

.formation-types-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 1.5rem;
  margin-top: 1.5rem;
}

.formation-type-card {
  background: white;
  padding: 1.5rem;
  border-radius: 0.75rem;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  border: 1px solid #e5e7eb;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.formation-type-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
}

.formation-type-card h4 {
  color: #1f2937;
  margin-bottom: 1rem;
  font-size: 1.1rem;
  font-weight: 600;
}

.formation-type-card ul {
  list-style: none;
  padding: 0;
  margin: 0;
}

.formation-type-card li {
  margin-bottom: 0.5rem;
  padding: 0.5rem;
  background: #f9fafb;
  border-radius: 0.375rem;
  border-left: 3px solid #3b82f6;
}

.formation-link {
  color: #2563eb;
  text-decoration: none;
  font-weight: 500;
  transition: color 0.2s ease;
}

.formation-link:hover {
  color: #1d4ed8;
  text-decoration: underline;
}

/* Liens vers calendrier dans les sections */
.text-blue-600 {
  color: #2563eb;
}

.text-blue-600:hover {
  color: #1d4ed8;
}

/* Responsive */
@media (max-width: 768px) {
  .formation-types-grid {
    grid-template-columns: 1fr;
  }

  .training-navigation nav ul {
    justify-content: center;
  }
}
